import { FastifyRequest, FastifyReply } from 'fastify';
import { validate } from 'class-validator';
import { ILeaveManagementService } from '../../leave/leave.service';
import { UserContext } from '../../auth/auth.types';
import {
  CreateLeaveRequestDto,
  ApproveLeaveRequestDto,
  RejectLeaveRequestDto,
  CancelLeaveRequestDto,
  DiscardLeaveRequestDto,
  LeaveRequestResponse,
  LeaveBalanceResponse,
} from './leave.dto';

type AuthenticatedRequest = FastifyRequest & { user: UserContext };

export class LeaveController {
  constructor(private readonly leaveService: ILeaveManagementService) {}

  async submit(request: FastifyRequest<{ Body: CreateLeaveRequestDto }>, reply: FastifyReply): Promise<void> {
    try {
      const dto = Object.assign(new CreateLeaveRequestDto(), request.body);
      const errors = await validate(dto);
      if (errors.length > 0) {
        return reply.status(400).send({ message: 'Validation failed', errors });
      }
      const authReq = request as AuthenticatedRequest;
      const result = await this.leaveService.submitLeaveRequest(authReq.user.employeeId, dto);
      return reply.status(201).send(result);
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  }

  async approve(request: FastifyRequest<{ Params: { id: string }; Body: ApproveLeaveRequestDto }>, reply: FastifyReply): Promise<void> {
    try {
      const dto = Object.assign(new ApproveLeaveRequestDto(), request.body);
      const errors = await validate(dto);
      if (errors.length > 0) {
        return reply.status(400).send({ message: 'Validation failed', errors });
      }
      const authReq = request as AuthenticatedRequest;
      const result = await this.leaveService.approveLeaveRequest(request.params.id, authReq.user.employeeId, dto.comment);
      return reply.status(200).send(result);
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  }

  async reject(request: FastifyRequest<{ Params: { id: string }; Body: RejectLeaveRequestDto }>, reply: FastifyReply): Promise<void> {
    try {
      const dto = Object.assign(new RejectLeaveRequestDto(), request.body);
      const errors = await validate(dto);
      if (errors.length > 0) {
        return reply.status(400).send({ message: 'Validation failed', errors });
      }
      const authReq = request as AuthenticatedRequest;
      const result = await this.leaveService.rejectLeaveRequest(request.params.id, authReq.user.employeeId, dto.comment);
      return reply.status(200).send(result);
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  }

  async cancel(request: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply): Promise<void> {
    try {
      const authReq = request as AuthenticatedRequest;
      const result = await this.leaveService.cancelLeaveRequest(request.params.id, authReq.user.employeeId);
      return reply.status(200).send(result);
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  }

  async discard(request: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply): Promise<void> {
    try {
      const authReq = request as AuthenticatedRequest;
      await this.leaveService.discardDraftLeaveRequest(request.params.id, authReq.user.employeeId);
      return reply.status(204).send();
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  }

  async history(request: FastifyRequest, reply: FastifyReply): Promise<void> {
    try {
      const authReq = request as AuthenticatedRequest;
      const result = await this.leaveService.getLeaveHistory(authReq.user.employeeId);
      return reply.status(200).send(result);
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  }

  async balances(request: FastifyRequest, reply: FastifyReply): Promise<void> {
    try {
      const authReq = request as AuthenticatedRequest;
      const result = await this.leaveService.getLeaveBalances(authReq.user.employeeId);
      return reply.status(200).send(result);
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  }
}","File: src/modules/leave-api/leave.routes.ts
import { FastifyInstance } from 'fastify';
import { ILeaveManagementService } from '../../leave/leave.service';
import { authenticate, authorize } from '../../auth/auth.middleware';
import { LeaveController } from './leave.controller';

export function registerLeaveRoutes(server: FastifyInstance, leaveService: ILeaveManagementService): void {
  const controller = new LeaveController(leaveService);

  server.post('/api/leave/submit', {
    preHandler: [authenticate, authorize('employee')],
  }, controller.submit.bind(controller));

  server.put('/api/leave/approve/:id', {
    preHandler: [authenticate, authorize('manager')],
  }, controller.approve.bind(controller));

  server.put('/api/leave/reject/:id', {
    preHandler: [authenticate, authorize('manager')],
  }, controller.reject.bind(controller));

  server.put('/api/leave/cancel/:id', {
    preHandler: [authenticate, authorize('employee')],
  }, controller.cancel.bind(controller));

  server.delete('/api/leave/discard-draft/:id', {
    preHandler: [authenticate, authorize('employee')],
  }, controller.discard.bind(controller));

  server.get('/api/leave/history', {
    preHandler: [authenticate, authorize('employee')],
  }, controller.history.bind(controller));

  server.get('/api/leave/balances', {
    preHandler: [authenticate, authorize('employee')],
  }, controller.balances.bind(controller));
}","File: tests/unit/modules/leave-api/leave.controller.test.ts
