describe('LeaveController', () => {
  let controller: LeaveController;
  let mockLeaveService: jest.Mocked<ILeaveManagementService>;
  let mockReply: Partial<FastifyReply>;

  const mockUser: UserContext = { employeeId: 'emp-1', role: 'employee', userId: 'user-1' };

  function createMockRequest(overrides: any = {}): Partial<FastifyRequest> {
    return {
      body: {},
      params: {},
      user: mockUser,
      ...overrides,
    };
  }

  beforeEach(() => {
    mockLeaveService = {
      submitLeaveRequest: jest.fn(),
      approveLeaveRequest: jest.fn(),
      rejectLeaveRequest: jest.fn(),
      cancelLeaveRequest: jest.fn(),
      discardDraftLeaveRequest: jest.fn(),
      getLeaveHistory: jest.fn(),
      getLeaveBalances: jest.fn(),
    } as any;
    controller = new LeaveController(mockLeaveService);
    mockReply = {
      status: jest.fn().mockReturnThis(),
      send: jest.fn().mockReturnThis(),
    };
  });

  describe('submit', () => {
    it('should return 201 with created leave request', async () => {
      const dto = { leaveTypeId: 'type-1', startDate: '2025-01-01', endDate: '2025-01-03', reason: 'vacation' };
      const created = { id: 'lr-1', ...dto, employeeId: 'emp-1', status: 'submitted', managerComment: null, createdAt: '', updatedAt: '' };
      mockLeaveService.submitLeaveRequest.mockResolvedValue(created);
      const req = createMockRequest({ body: dto });
      await controller.submit(req as any, mockReply as any);
      expect(mockLeaveService.submitLeaveRequest).toHaveBeenCalledWith('emp-1', expect.objectContaining(dto));
      expect(mockReply.status).toHaveBeenCalledWith(201);
      expect(mockReply.send).toHaveBeenCalledWith(created);
    });

    it('should return 400 on validation error', async () => {
      const req = createMockRequest({ body: { leaveTypeId: 'invalid' } });
      await controller.submit(req as any, mockReply as any);
      expect(mockReply.status).toHaveBeenCalledWith(400);
    });

    it('should return 500 on service error', async () => {
      mockLeaveService.submitLeaveRequest.mockRejectedValue(new Error('DB error'));
      const req = createMockRequest({ body: { leaveTypeId: 'type-1', startDate: '2025-01-01', endDate: '2025-01-03' } });
      await controller.submit(req as any, mockReply as any);
      expect(mockReply.status).toHaveBeenCalledWith(500);
    });
  });

