    it('should return 200 with approved request', async () => {
      const approved = { id: 'lr-1', status: 'approved' };
      mockLeaveService.approveLeaveRequest.mockResolvedValue(approved);
      const req = createMockRequest({ params: { id: 'lr-1' }, body: { comment: 'ok' } });
      await controller.approve(req as any, mockReply as any);
      expect(mockLeaveService.approveLeaveRequest).toHaveBeenCalledWith('lr-1', 'emp-1', 'ok');
      expect(mockReply.status).toHaveBeenCalledWith(200);
      expect(mockReply.send).toHaveBeenCalledWith(approved);
    });
  });

  describe('reject', () => {
    it('should return 200 with rejected request', async () => {
      const rejected = { id: 'lr-1', status: 'rejected' };
      mockLeaveService.rejectLeaveRequest.mockResolvedValue(rejected);
      const req = createMockRequest({ params: { id: 'lr-1' }, body: { comment: 'denied' } });
      await controller.reject(req as any, mockReply as any);
      expect(mockLeaveService.rejectLeaveRequest).toHaveBeenCalledWith('lr-1', 'emp-1', 'denied');
      expect(mockReply.status).toHaveBeenCalledWith(200);
      expect(mockReply.send).toHaveBeenCalledWith(rejected);
    });
  });

  describe('cancel', () => {
    it('should return 200 with cancelled request', async () => {
      const cancelled = { id: 'lr-1', status: 'cancelled' };
      mockLeaveService.cancelLeaveRequest.mockResolvedValue(cancelled);
      const req = createMockRequest({ params: { id: 'lr-1' } });
      await controller.cancel(req as any, mockReply as any);
      expect(mockLeaveService.cancelLeaveRequest).toHaveBeenCalledWith('lr-1', 'emp-1');
      expect(mockReply.status).toHaveBeenCalledWith(200);
      expect(mockReply.send).toHaveBeenCalledWith(cancelled);
    });
  });

  describe('discard', () => {
    it('should return 204 on successful discard', async () => {
      mockLeaveService.discardDraftLeaveRequest.mockResolvedValue(undefined);
      const req = createMockRequest({ params: { id: 'lr-1' } });
      await controller.discard(req as any, mockReply as any);
      expect(mockLeaveService.discardDraftLeaveRequest).toHaveBeenCalledWith('lr-1', 'emp-1');
      expect(mockReply.status).toHaveBeenCalledWith(204);
      expect(mockReply.send).toHaveBeenCalled();
    });
  });

  describe('history', () => {
    it('should return 200 with leave history', async () => {
      const history = [{ id: 'lr-1' }];
      mockLeaveService.getLeaveHistory.mockResolvedValue(history);
      const req = createMockRequest();
      await controller.history(req as any, mockReply as any);
      expect(mockLeaveService.getLeaveHistory).toHaveBeenCalledWith('emp-1');
      expect(mockReply.status).toHaveBeenCalledWith(200);
      expect(mockReply.send).toHaveBeenCalledWith(history);
    });
  });

  describe('balances', () => {
    it('should return 200 with balances', async () => {
      const balances = [{ leaveTypeId: 'type-1', balance: 10, year: 2025 }];
      mockLeaveService.getLeaveBalances.mockResolvedValue(balances);
      const req = createMockRequest();
      await controller.balances(req as any, mockReply as any);
      expect(mockLeaveService.getLeaveBalances).toHaveBeenCalledWith('emp-1');
      expect(mockReply.status).toHaveBeenCalledWith(200);
      expect(mockReply.send).toHaveBeenCalledWith(balances);
    });
  });
