import { ILeaveManagementService } from '../leave/leave.service';
import { UserContext } from '../auth/auth.types';
import { CreateLeaveRequestDto, ApproveLeaveRequestDto, RejectLeaveRequestDto, CancelLeaveRequestDto, DiscardLeaveRequestDto, LeaveRequestResponse, LeaveBalanceResponse } from './leave.dto';
import { validate } from 'class-validator';

export class LeaveController {
  constructor(private readonly leaveService: ILeaveManagementService) {}

  async submitLeave(req: FastifyRequest<{ Body: CreateLeaveRequestDto }>, reply: FastifyReply): Promise<void> {
    const user: UserContext = (req as any).user;
    const dto = req.body;
    const errors = await validate(dto);
    if (errors.length > 0) {
      return reply.status(400).send({ message: 'Validation failed', errors });
    }
    const result = await this.leaveService.submitLeaveRequest(user.employeeId, dto);
    return reply.status(201).send(result);
  }

  async approveLeave(req: FastifyRequest<{ Params: { id: string }; Body: ApproveLeaveRequestDto }>, reply: FastifyReply): Promise<void> {
    const user: UserContext = (req as any).user;
    const { id } = req.params;
    const dto = req.body;
    const errors = await validate(dto);
    if (errors.length > 0) {
      return reply.status(400).send({ message: 'Validation failed', errors });
    }
    const result = await this.leaveService.approveLeaveRequest(id, user.employeeId, dto.comment);
    return reply.status(200).send(result);
  }

  async rejectLeave(req: FastifyRequest<{ Params: { id: string }; Body: RejectLeaveRequestDto }>, reply: FastifyReply): Promise<void> {
    const user: UserContext = (req as any).user;
    const { id } = req.params;
    const dto = req.body;
    const errors = await validate(dto);
    if (errors.length > 0) {
      return reply.status(400).send({ message: 'Validation failed', errors });
    }
    const result = await this.leaveService.rejectLeaveRequest(id, user.employeeId, dto.comment);
    return reply.status(200).send(result);
  }

  async cancelLeave(req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply): Promise<void> {
    const user: UserContext = (req as any).user;
    const { id } = req.params;
    const result = await this.leaveService.cancelLeaveRequest(id, user.employeeId);
    return reply.status(200).send(result);
  }

  async discardDraft(req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply): Promise<void> {
    const user: UserContext = (req as any).user;
    const { id } = req.params;
    await this.leaveService.discardDraftLeaveRequest(id, user.employeeId);
    return reply.status(204).send();
  }

  async getBalances(req: FastifyRequest, reply: FastifyReply): Promise<void> {
    const user: UserContext = (req as any).user;
    const balances = await this.leaveService.getLeaveBalances(user.employeeId);
